def gen(rng, size):
    budget = [max(1, min(size, 120))]
    def build(depth):
        out = []
        items = rng.randint(0 if depth else 1, 4)
        for _ in range(items):
            if budget[0] <= 0:
                break
            if depth < 5 and rng.random() < 0.35:
                out.append(build(depth + 1))
            else:
                budget[0] -= 1
                out.append(rng.randint(-1000000, 1000000))
        return out
    nested = build(0)
    def count(v):
        if isinstance(v, int):
            return 1
        return sum(count(x) for x in v)
    total = count(nested)
    if total == 0:
        nested.append(rng.randint(-1000000, 1000000))
        total = 1
    ops = ['NestedIterator']
    args = [[nested]]
    for _ in range(total):
        if rng.random() < 0.5:
            ops.append('hasNext')
            args.append([])
        ops.append('next')
        args.append([])
    ops.append('hasNext')
    args.append([])
    return [ops, args]

