class NestedIterator:
    def __init__(self, nestedList):
        self.vals = []
        def dig(items):
            for item in items:
                if item.isInteger():
                    self.vals.append(item.getInteger())
                else:
                    dig(item.getList())
        dig(nestedList)
        self.i = 0
    def next(self) -> int:
        v = self.vals[self.i]
        self.i += 1
        return v
    def hasNext(self) -> bool:
        return self.i < len(self.vals)

